import type { Component } from "vue";

import type {
  MusicBrowserPlaybackTrack,
  PlayTrackResult,
} from "../../../types/music/MusicBrowserTrack";
import MusicBrowserApp from "../../../view/apps/music-browser/MusicBrowserApp.vue";
import { MODULE_ID, MODULE_TITLE } from "../../constants";
import { playBrowserTrack } from "../../music/play-browser-track";
import { FoundryVueApplication } from "../FoundryVueApplication";

export class MusicBrowserApplication extends FoundryVueApplication {
  static override DEFAULT_OPTIONS = {
    id: `${MODULE_ID}-music-browser`,
    tag: "section",
    window: {
      icon: "fa-solid fa-music",
      resizable: true,
      title: MODULE_TITLE,
    },
    position: {
      height: 720,
      width: 980,
    },
  };

  protected override getVueComponent(): Component {
    return MusicBrowserApp;
  }

  protected override getVueProps(): Record<string, unknown> {
    return {
      onPlayTrack: async (track: MusicBrowserPlaybackTrack): Promise<PlayTrackResult> =>
        playBrowserTrack(track),
    };
  }
}
