<script setup lang="ts">
import { computed } from "vue";

import type { MusicBrowserTrack } from "../../../types/music/MusicBrowserTrack";

const props = defineProps<{
  busy: boolean;
  selectedTag: string;
  track: MusicBrowserTrack;
}>();

const emit = defineEmits<{
  play: [track: MusicBrowserTrack];
  selectTag: [tag: string];
}>();

const ratingMetrics = computed(() => [
  { label: "Energy", value: props.track.ratings.intensity },
  { label: "Dark", value: props.track.ratings.darkness },
  { label: "Tension", value: props.track.ratings.tension },
  { label: "Strange", value: props.track.ratings.weirdness },
]);

function confidenceLabel(value: MusicBrowserTrack["confidence"]): string {
  return value === "unreviewed" ? "Not reviewed" : `${value} confidence`;
}
</script>

<template>
  <article class="tw:dui-card tw:dui-card-sm track-card">
    <div class="tw:dui-card-body tw:gap-3">
      <div class="tw:flex tw:items-start tw:justify-between tw:gap-3">
        <div class="tw:min-w-0">
          <p class="track-catalog-line">
            <span>{{ track.album }}</span>
            <span aria-hidden="true">·</span>
            <span>Track {{ track.trackNumber }}</span>
          </p>
          <h2 class="tw:dui-card-title tw:mt-1 tw:text-xl">{{ track.rpgTitle }}</h2>
        </div>

        <button
          :aria-label="`Play ${track.rpgTitle}`"
          class="tw:dui-btn tw:dui-btn-sm tw:min-w-24 tw:shrink-0"
          :disabled="busy"
          type="button"
          @click="emit('play', track)"
        >
          <span aria-hidden="true">{{ busy ? "…" : "▶" }}</span>
          {{ busy ? "Starting" : "Play" }}
        </button>
      </div>

      <p class="track-cue">{{ track.gmCue }}</p>

      <div class="tw:flex tw:flex-wrap tw:gap-1.5" aria-label="Scene tags">
        <button
          v-for="tag in track.tags"
          :key="`${track.id}-${tag}`"
          :aria-pressed="selectedTag === tag"
          class="tw:dui-badge tw:dui-badge-sm track-tag"
          :class="{ 'tw:dui-badge-neutral': selectedTag === tag }"
          type="button"
          @click="emit('selectTag', tag)"
        >
          {{ tag.replaceAll("-", " ") }}
        </button>
      </div>

      <div class="mood-grid" aria-label="Track mood ratings">
        <div
          v-for="metric in ratingMetrics"
          :key="metric.label"
          class="mood-meter"
          :aria-label="`${metric.label}: ${metric.value ?? 'not rated'} out of 5`"
        >
          <span>{{ metric.label }}</span>
          <span class="mood-dots" aria-hidden="true">
            <i
              v-for="point in 5"
              :key="point"
              :class="{ 'is-filled': metric.value !== null && point <= metric.value }"
            ></i>
          </span>
        </div>
      </div>

      <details class="track-details">
        <summary>Why it fits &amp; track details</summary>
        <div class="tw:grid tw:gap-2 tw:pt-3">
          <p>{{ track.notes }}</p>
          <p class="track-official-title">
            <span>Official track</span>
            <strong>{{ track.officialTitle }}</strong>
          </p>
          <div class="tw:flex tw:flex-wrap tw:gap-1.5">
            <span class="tw:dui-badge tw:dui-badge-ghost tw:dui-badge-sm">
              {{ confidenceLabel(track.confidence) }}
            </span>
            <span class="tw:dui-badge tw:dui-badge-ghost tw:dui-badge-sm">
              {{ track.researchSources.length }} research sources
            </span>
          </div>
        </div>
      </details>
    </div>
  </article>
</template>
