import type {
  MusicBrowserPlaybackTrack,
  PlayTrackResult,
} from "../../types/music/MusicBrowserTrack";
import { MODULE_ID } from "../constants";

const BROWSER_PLAYLIST_NAME = "NIN Ghosts RPG Browser";

export async function playBrowserTrack(track: MusicBrowserPlaybackTrack): Promise<PlayTrackResult> {
  const playlist = await getOrCreateBrowserPlaylist();
  const sound = await getOrCreatePlaylistSound(playlist, track);

  if (playlist.playSound) {
    await playlist.playSound(sound);
    return { ok: true, message: `Playing ${track.title}.` };
  }

  if (sound.play) {
    await sound.play();
    return { ok: true, message: `Playing ${track.title}.` };
  }

  return {
    ok: false,
    message: "Foundry did not expose a playlist playback method for this track.",
  };
}

async function getOrCreateBrowserPlaylist(): Promise<foundry.documents.Playlist> {
  const existingPlaylist = findPlaylistByName(BROWSER_PLAYLIST_NAME);

  if (existingPlaylist) {
    return existingPlaylist;
  }

  if (typeof Playlist === "undefined") {
    throw new Error("Foundry Playlist document constructor is unavailable.");
  }

  return Playlist.create({
    channel: "music",
    description: "Tracks launched from the NIN Ghosts RPG music browser.",
    flags: {
      [MODULE_ID]: {
        browserPlaylist: true,
      },
    },
    mode: 0,
    name: BROWSER_PLAYLIST_NAME,
    playing: false,
    sounds: [],
  });
}

async function getOrCreatePlaylistSound(
  playlist: foundry.documents.Playlist,
  track: MusicBrowserPlaybackTrack,
): Promise<foundry.documents.PlaylistSound> {
  const existingSound = getPlaylistSounds(playlist).find((sound) => {
    const flags = sound.flags?.[MODULE_ID];
    return flags?.["trackId"] === track.id || sound.path === track.path;
  });

  if (existingSound) {
    return existingSound;
  }

  if (!playlist.createEmbeddedDocuments) {
    throw new Error("Foundry did not expose playlist sound creation for the browser playlist.");
  }

  const [sound] = await playlist.createEmbeddedDocuments("PlaylistSound", [
    {
      channel: "music",
      description: "Created by the NIN Ghosts RPG music browser.",
      fade: null,
      flags: {
        [MODULE_ID]: {
          trackId: track.id,
        },
      },
      name: track.title,
      path: track.path,
      pausedTime: null,
      playing: false,
      repeat: false,
      volume: 0.5,
    },
  ]);

  if (!sound) {
    throw new Error("Foundry did not return the created playlist sound.");
  }

  return sound;
}

function findPlaylistByName(name: string): foundry.documents.Playlist | undefined {
  const playlists = game?.playlists;

  if (!playlists) {
    return undefined;
  }

  return playlists.getName?.(name) ?? getPlaylists().find((playlist) => playlist.name === name);
}

function getPlaylists(): foundry.documents.Playlist[] {
  const playlists = game?.playlists;

  if (!playlists) {
    return [];
  }

  if (playlists.contents) {
    return playlists.contents;
  }

  if (playlists.values) {
    return Array.from(playlists.values());
  }

  return [];
}

function getPlaylistSounds(
  playlist: foundry.documents.Playlist,
): foundry.documents.PlaylistSound[] {
  const sounds = playlist.sounds;

  if (!sounds) {
    return [];
  }

  if (Array.isArray(sounds)) {
    return sounds;
  }

  if (sounds.contents) {
    return sounds.contents;
  }

  if (sounds.values) {
    return Array.from(sounds.values());
  }

  return [];
}
