import type { MusicBrowserTrack } from "../../types/music/MusicBrowserTrack";

export type MusicBrowserEnergyFilter = "" | "high" | "low" | "medium";

export interface MusicBrowserFilters {
  album: string;
  energy: MusicBrowserEnergyFilter;
  query: string;
  tag: string;
}

interface ScoredTrack {
  score: number;
  track: MusicBrowserTrack;
}

export function filterMusicBrowserTracks(
  tracks: MusicBrowserTrack[],
  filters: MusicBrowserFilters,
): MusicBrowserTrack[] {
  const queryTokens = normalize(filters.query).split(" ").filter(Boolean);

  return tracks
    .filter((track) => matchesStructuredFilters(track, filters))
    .map((track, index): ScoredTrack & { index: number } => ({
      index,
      score: scoreSearchMatch(track, queryTokens),
      track,
    }))
    .filter(({ score }) => queryTokens.length === 0 || score > 0)
    .sort((left, right) => right.score - left.score || left.index - right.index)
    .map(({ track }) => track);
}

function matchesStructuredFilters(track: MusicBrowserTrack, filters: MusicBrowserFilters): boolean {
  if (filters.album && track.album !== filters.album) {
    return false;
  }

  if (filters.tag && !track.tags.includes(filters.tag)) {
    return false;
  }

  const intensity = track.ratings.intensity;

  if (!filters.energy || intensity === null) {
    return !filters.energy;
  }

  if (filters.energy === "low") {
    return intensity <= 2;
  }

  if (filters.energy === "medium") {
    return intensity === 3;
  }

  return intensity >= 4;
}

function scoreSearchMatch(track: MusicBrowserTrack, tokens: string[]): number {
  if (tokens.length === 0) {
    return 0;
  }

  const fields = {
    album: normalize(track.album),
    cue: normalize(track.gmCue),
    notes: normalize(track.notes),
    officialTitle: normalize(track.officialTitle),
    rpgTitle: normalize(track.rpgTitle),
    tags: track.tags.map(normalize),
  };
  const searchableText = Object.values(fields).flat().join(" ");

  if (!tokens.every((token) => searchableText.includes(token))) {
    return 0;
  }

  return tokens.reduce((score, token) => {
    if (fields.rpgTitle.includes(token)) score += 8;
    if (fields.tags.some((tag) => tag.includes(token))) score += 6;
    if (fields.cue.includes(token)) score += 4;
    if (fields.officialTitle.includes(token)) score += 2;
    if (fields.album.includes(token)) score += 1;
    if (fields.notes.includes(token)) score += 1;
    return score;
  }, 0);
}

function normalize(value: string): string {
  return value.trim().toLowerCase().replaceAll("-", " ").replaceAll(/\s+/g, " ");
}
