<script setup lang="ts">
import { computed, onMounted, ref } from "vue";

import {
  filterMusicBrowserTracks,
  type MusicBrowserEnergyFilter,
} from "../../../functions/music/filter-music-browser-tracks";
import { loadMusicBrowserTracks } from "../../../functions/music/create-music-browser-catalog";
import type {
  MusicBrowserPlaybackTrack,
  MusicBrowserTrack,
  PlayTrackResult,
} from "../../../types/music/MusicBrowserTrack";
import MusicTrackCard from "./MusicTrackCard.vue";

const props = defineProps<{
  onPlayTrack?: (track: MusicBrowserPlaybackTrack) => Promise<PlayTrackResult>;
}>();

const QUICK_TAGS = [
  { label: "Explore", value: "exploration" },
  { label: "Investigate", value: "investigation" },
  { label: "Sneak", value: "stealth" },
  { label: "Fight", value: "combat" },
  { label: "Horror", value: "horror" },
  { label: "Recover", value: "recovery" },
  { label: "Travel", value: "travel" },
] as const;

const albumFilter = ref("");
const busyTrackId = ref("");
const energyFilter = ref<MusicBrowserEnergyFilter>("");
const loadingMessage = ref("Loading the track catalog…");
const playStatus = ref<({ id: string } & PlayTrackResult) | null>(null);
const searchText = ref("");
const selectedTag = ref("");
const tracks = ref<MusicBrowserTrack[]>([]);

const albums = computed(() =>
  Array.from(new Set(tracks.value.map((track) => track.album))).sort((left, right) =>
    left.localeCompare(right),
  ),
);
const filteredTracks = computed(() =>
  filterMusicBrowserTracks(tracks.value, {
    album: albumFilter.value,
    energy: energyFilter.value,
    query: searchText.value,
    tag: selectedTag.value,
  }),
);
const hasFilters = computed(() =>
  Boolean(albumFilter.value || energyFilter.value || searchText.value || selectedTag.value),
);
const tags = computed(() =>
  Array.from(new Set(tracks.value.flatMap((track) => track.tags))).sort((left, right) =>
    left.localeCompare(right),
  ),
);

onMounted(async () => {
  try {
    tracks.value = await loadMusicBrowserTracks();
    loadingMessage.value = "";
  } catch (error) {
    loadingMessage.value =
      error instanceof Error ? error.message : "The track catalog could not be loaded.";
  }
});

function clearFilters(): void {
  albumFilter.value = "";
  energyFilter.value = "";
  searchText.value = "";
  selectedTag.value = "";
}

function selectTag(tag: string): void {
  selectedTag.value = selectedTag.value === tag ? "" : tag;
}

async function playTrack(track: MusicBrowserTrack): Promise<void> {
  busyTrackId.value = track.id;

  try {
    const result = props.onPlayTrack
      ? await props.onPlayTrack({ id: track.id, path: track.path, title: track.title })
      : { message: `Preview selected ${track.title}.`, ok: true };
    playStatus.value = { ...result, id: track.id };
  } catch (error) {
    playStatus.value = {
      id: track.id,
      message: error instanceof Error ? error.message : "The track could not be started.",
      ok: false,
    };
  } finally {
    busyTrackId.value = "";
  }
}
</script>

<template>
  <main class="music-browser">
    <header class="browser-header">
      <p class="browser-kicker">NIN Ghosts · GM score finder</p>
      <h1>Find the right track for the scene.</h1>
      <p class="browser-intro">
        Describe the moment, pick a scene type, or dial in the energy. The catalog is curated for
        play at the table.
      </p>

      <label class="tw:dui-input tw:dui-input-lg browser-search">
        <span aria-hidden="true" class="tw:text-xl">⌕</span>
        <input
          v-model="searchText"
          aria-label="Describe the scene"
          class="tw:grow"
          placeholder="Try “quiet investigation”, “ruins”, or “frantic escape”…"
          type="search"
        />
        <button
          v-if="searchText"
          aria-label="Clear search"
          class="tw:dui-btn tw:dui-btn-circle tw:dui-btn-ghost tw:dui-btn-sm"
          type="button"
          @click="searchText = ''"
        >
          ×
        </button>
      </label>

      <div class="quick-filters" aria-label="Quick scene filters">
        <span>Quick scenes</span>
        <button
          v-for="tag in QUICK_TAGS"
          :key="tag.value"
          :aria-pressed="selectedTag === tag.value"
          class="tw:dui-btn tw:dui-btn-xs"
          :class="{ 'tw:dui-btn-neutral': selectedTag === tag.value }"
          type="button"
          @click="selectTag(tag.value)"
        >
          {{ tag.label }}
        </button>
      </div>

      <div class="browser-filters">
        <label>
          <span>Album</span>
          <select v-model="albumFilter" class="tw:dui-select tw:dui-select-sm tw:w-full">
            <option value="">Every album</option>
            <option v-for="album in albums" :key="album" :value="album">{{ album }}</option>
          </select>
        </label>
        <label>
          <span>Energy</span>
          <select v-model="energyFilter" class="tw:dui-select tw:dui-select-sm tw:w-full">
            <option value="">Any energy</option>
            <option value="low">Low · 1–2</option>
            <option value="medium">Medium · 3</option>
            <option value="high">High · 4–5</option>
          </select>
        </label>
        <label>
          <span>Scene tag</span>
          <select v-model="selectedTag" class="tw:dui-select tw:dui-select-sm tw:w-full">
            <option value="">Any scene</option>
            <option v-for="tag in tags" :key="tag" :value="tag">
              {{ tag.replaceAll("-", " ") }}
            </option>
          </select>
        </label>
        <button
          class="tw:dui-btn tw:dui-btn-sm tw:self-end"
          :disabled="!hasFilters"
          type="button"
          @click="clearFilters"
        >
          Reset
        </button>
      </div>
    </header>

    <section class="browser-results" aria-labelledby="results-heading">
      <div class="results-heading-row">
        <div>
          <h2 id="results-heading">Tracks for your scene</h2>
          <p aria-live="polite">
            {{ filteredTracks.length }} {{ filteredTracks.length === 1 ? "match" : "matches" }}
            <span v-if="hasFilters"> in the 59-track library</span>
          </p>
        </div>
        <p v-if="selectedTag" class="tw:dui-badge tw:dui-badge-neutral tw:gap-1">
          {{ selectedTag.replaceAll("-", " ") }}
          <button aria-label="Remove scene tag filter" type="button" @click="selectedTag = ''">
            ×
          </button>
        </p>
      </div>

      <div
        v-if="playStatus"
        class="tw:dui-alert tw:mb-3"
        :class="playStatus.ok ? 'tw:dui-alert-success' : 'tw:dui-alert-error'"
        role="status"
      >
        <span aria-hidden="true">{{ playStatus.ok ? "▶" : "!" }}</span>
        <span>{{ playStatus.message }}</span>
      </div>

      <div v-if="loadingMessage" class="tw:dui-alert" role="status">
        <span
          class="tw:dui-loading tw:dui-loading-sm tw:dui-loading-spinner"
          aria-hidden="true"
        ></span>
        <span>{{ loadingMessage }}</span>
      </div>

      <div v-else-if="filteredTracks.length" class="track-grid">
        <MusicTrackCard
          v-for="track in filteredTracks"
          :key="track.id"
          :busy="busyTrackId === track.id"
          :selected-tag="selectedTag"
          :track="track"
          @play="playTrack"
          @select-tag="selectTag"
        />
      </div>

      <div v-else class="empty-results">
        <span aria-hidden="true">⌕</span>
        <h3>No tracks fit all of those choices.</h3>
        <p>Try fewer words, a different energy level, or clear the scene tag.</p>
        <button class="tw:dui-btn tw:dui-btn-sm" type="button" @click="clearFilters">
          Show all tracks
        </button>
      </div>
    </section>
  </main>
</template>
