import type { MusicBrowserRatings, MusicBrowserTrack } from "../../types/music/MusicBrowserTrack";

interface MusicBrowserManifestTrack {
  album: string;
  albumId: string;
  annotationStatus: MusicBrowserTrack["annotationStatus"];
  confidence: MusicBrowserTrack["confidence"];
  gmCue: string;
  id: string;
  notes: string;
  officialTitle: string;
  path: string;
  ratings: MusicBrowserRatings;
  researchSources: string[];
  rpgTitle: string;
  tags: string[];
  trackNumber: string;
  verificationSources: string[];
  verificationStatus: MusicBrowserTrack["verificationStatus"];
}

interface MusicBrowserManifest {
  tracks: MusicBrowserManifestTrack[];
}

const MANIFEST_PATHS = [
  "/modules/fvtt-nin-ghosts-annotated/catalog/nin-ghosts-track-manifest.json",
  "/catalog/nin-ghosts-track-manifest.json",
];

export async function loadMusicBrowserTracks(
  fetcher: typeof fetch = fetch,
): Promise<MusicBrowserTrack[]> {
  const manifest = await loadManifest(fetcher);
  return createMusicBrowserTracks(manifest);
}

export function createMusicBrowserTracks(manifest: MusicBrowserManifest): MusicBrowserTrack[] {
  return manifest.tracks.map((track) => ({
    ...track,
    title: track.officialTitle.startsWith(track.trackNumber)
      ? track.officialTitle
      : `${track.trackNumber} ${track.officialTitle}`,
  }));
}

async function loadManifest(fetcher: typeof fetch): Promise<MusicBrowserManifest> {
  let lastError: unknown;

  for (const path of MANIFEST_PATHS) {
    try {
      const response = await fetcher(path);

      if (response.ok) {
        return (await response.json()) as MusicBrowserManifest;
      }

      lastError = new Error(`Track manifest request failed with ${response.status} for ${path}.`);
    } catch (error) {
      lastError = error;
    }
  }

  throw lastError instanceof Error
    ? lastError
    : new Error("Music browser track manifest could not be loaded.");
}
